function parseCsv(text) {
  const lines = text.trim().split(/\r?\n/);
  const headers = lines[0].split(',');
  return lines.slice(1).filter(Boolean).map((line) => {
    const values = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') {
          current += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === ',' && !inQuotes) {
        values.push(current);
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current);
    return Object.fromEntries(headers.map((header, index) => [header, values[index] ?? '']));
  });
}

function toNumber(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function sigmoid(value) {
  return 1 / (1 + Math.exp(-value));
}

function decisionLabel(probability, thresholds) {
  if (probability >= thresholds.decline) return 'Decline';
  if (probability >= thresholds.review) return 'Review';
  return 'Approve';
}

function formatUsd(value) {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(value);
}

function contributionReason(detail) {
  if (detail.field === 'credit_score') {
    if (detail.rawValue < 600) return `Low credit score (${Math.round(detail.rawValue)}) materially increases default risk.`;
    return `Credit score (${Math.round(detail.rawValue)}) is below the stronger-performing borrower range.`;
  }
  if (detail.field === 'debt_to_income_ratio') {
    return `Debt-to-income ratio (${detail.rawValue.toFixed(2)}) is high relative to the training portfolio.`;
  }
  if (detail.field === 'interest_rate_pct') {
    return `Interest rate (${detail.rawValue.toFixed(2)}%) is elevated versus lower-risk borrowers.`;
  }
  if (detail.field === 'loan_amount_usd') {
    return `Requested loan amount (${formatUsd(detail.rawValue)}) is large for this portfolio.`;
  }
  if (detail.field === 'annual_revenue_usd') {
    return `Annual revenue (${formatUsd(detail.rawValue)}) is low relative to requested credit.`;
  }
  if (detail.field === 'business_age_years') {
    return `Business operating history (${Math.round(detail.rawValue)} years) is limited.`;
  }
  if (detail.field === 'loan_term_months') {
    return `Loan term (${Math.round(detail.rawValue)} months) is longer than the lower-risk cohort.`;
  }
  if (detail.field === 'sector') {
    return `Sector exposure (${detail.rawValue}) has historically produced higher defaults in this sample.`;
  }
  if (detail.field === 'loan_purpose') {
    return `Loan purpose (${detail.rawValue}) has performed worse than the portfolio average.`;
  }
  if (detail.field === 'state') {
    return `State cohort (${detail.rawValue}) has a weaker repayment pattern in the training data.`;
  }
  return `${detail.field} contributes positively to risk.`;
}

function makeBrief(row, probability, decision, reasons) {
  const first = reasons[0] || 'The model found a weaker-than-average repayment profile.';
  const second = reasons[1] || 'No secondary driver rose materially above the rest.';
  const action = decision === 'Decline'
    ? 'Escalate for senior underwriter review and verify bank statements before issuing a final decline.'
    : 'Route to analyst review with refreshed cash-flow documents and recent bank statements.';
  return `RISK SUMMARY: ${decision} at ${(probability * 100).toFixed(1)}% default probability. ${first}\n\nKEY SIGNALS:\n- ${first}\n- ${second}\n\nANALYST ACTION: ${action}`;
}

